'use client';
import { useState } from 'react';
import Image from 'next/image';
import { useStore } from '../lib/store';
import { Gift, ArrowDown, ArrowLeft } from 'lucide-react';
import Link from 'next/link';

export default function Dashboard() {
  const [isLogged, setIsLogged] = useState(false);
  const [pass, setPass] = useState('');

  const [donation, setDonation] = useState({
    donorName: '', donorPhone: '', donorAddress: '', donorAvatar: '', donorPreview: null,
    receiverName: '', receiverPhone: '', receiverAddress: '', receiverAvatar: '', receiverPreview: null,
    amount: '', reason: ''
  });

  const [expense, setExpense] = useState({
    receiverName: '', receiverPhone: '', receiverAddress: '', receiverAvatar: '', receiverPreview: null,
    amount: '', reason: ''
  });

  const { members, addTransaction } = useStore();

  const handleLogin = () => {
    if (pass === 'admin123') {
      setIsLogged(true);
      setPass('');
    } else {
      alert('ভুল পাসওয়ার্ড!');
    }
  };

  const handleImageUpload = (e, type, formType = 'donation') => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      if (formType === 'donation') {
        if (type === 'donor') {
          setDonation({ ...donation, donorAvatar: reader.result, donorPreview: reader.result });
        } else {
          setDonation({ ...donation, receiverAvatar: reader.result, receiverPreview: reader.result });
        }
      } else {
        setExpense({ ...expense, receiverAvatar: reader.result, receiverPreview: reader.result });
      }
    };
    reader.readAsDataURL(file);
  };

  const base64ToFile = async (base64, filename) => {
    const res = await fetch(base64);
    const blob = await res.blob();
    return new File([blob], filename, { type: blob.type });
  };

  // DONATION SAVE
  const handleAddDonation = async () => {
    if (!donation.amount || Number(donation.amount) <= 0)
      return alert('দানের পরিমাণ লিখুন');

    if (!donation.donorName.trim())
      return alert('দাতার নাম লিখুন');

    if (!donation.receiverName.trim())
      return alert('গ্রহীতার নাম লিখুন');

    try {
      const formData = new FormData();

      formData.append("name", donation.donorName + " → " + donation.receiverName);
      formData.append("amount", donation.amount);
      formData.append("type", "donation");
      formData.append("note", donation.reason || "");

      if (donation.donorAvatar) {
        const file = await base64ToFile(donation.donorAvatar, "donor.png");
        formData.append("image", file);
      }

      const res = await fetch("http://localhost:5000/hishab", {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (data.success) {
        alert("দান সফলভাবে সেভ হয়েছে!");

        setDonation({
          donorName: '', donorPhone: '', donorAddress: '', donorAvatar: '', donorPreview: null,
          receiverName: '', receiverPhone: '', receiverAddress: '', receiverAvatar: '', receiverPreview: null,
          amount: '', reason: ''
        });
      } else {
        alert("সেভ হয়নি!");
      }

    } catch (err) {
      alert("Server error!");
    }
  };

  // EXPENSE SAVE
  const handleAddExpense = async () => {
    if (!expense.amount || Number(expense.amount) <= 0)
      return alert('খরচের পরিমাণ লিখুন');

    if (!expense.receiverName.trim())
      return alert('যাকে টাকা দেওয়া হলো তার নাম লিখুন');

    try {
      const formData = new FormData();

      formData.append("name", expense.receiverName);
      formData.append("amount", expense.amount);
      formData.append("type", "expense");
      formData.append("note", expense.reason || "");

      if (expense.receiverAvatar) {
        const file = await base64ToFile(expense.receiverAvatar, "expense.png");
        formData.append("image", file);
      }

      const res = await fetch("http://localhost:5000/hishab", {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (data.success) {
        alert("খরচ সফলভাবে সেভ হয়েছে!");

        setExpense({
          receiverName: '', receiverPhone: '', receiverAddress: '', receiverAvatar: '', receiverPreview: null,
          amount: '', reason: ''
        });
      } else {
        alert("সেভ হয়নি!");
      }

    } catch (err) {
      alert("Server error!");
    }
  };

  if (!isLogged) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-900 to-gray-800">
        <div className="bg-white/10 backdrop-blur-lg p-10 rounded-3xl shadow-2xl text-center max-w-md w-full border border-white/20">
          <h1 className="text-4xl font-bold mb-6 text-white">অ্যাডমিন লগইন</h1>
          <input
            type="password"
            placeholder="অ্যাডমিন পাসওয়ার্ড দিন"
            value={pass}
            onChange={(e) => setPass(e.target.value)}
            className="bg-white/20 border border-white/30 p-4 rounded-xl w-full text-xl mb-4 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-emerald-400"
          />
          <button
            onClick={handleLogin}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-4 rounded-xl w-full"
          >
            লগইন
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-6 md:p-10">
      <div className="max-w-7xl mx-auto">

        <div className="mb-10">
          <Link href="/">
            <button className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-xl">
              <ArrowLeft />
              হোমে ফিরে যান
            </button>
          </Link>
        </div>

        <h1 className="text-5xl font-extrabold mb-12 text-emerald-800 text-center">
          অ্যাডমিন ড্যাশবোর্ড
        </h1>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10 mb-16">

          {/* DONATION */}
          <div className="bg-white p-8 rounded-3xl shadow-2xl">
            <h2 className="text-3xl font-bold mb-8 text-purple-800 flex items-center gap-3">
              <Gift /> নতুন দান রেকর্ড
            </h2>

            <input
              placeholder="দাতার পূর্ণ নাম লিখুন"
              value={donation.donorName}
              onChange={(e) => setDonation({ ...donation, donorName: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="দাতার মোবাইল নাম্বার"
              value={donation.donorPhone}
              onChange={(e) => setDonation({ ...donation, donorPhone: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="দাতার ঠিকানা"
              value={donation.donorAddress}
              onChange={(e) => setDonation({ ...donation, donorAddress: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="গ্রহীতার পূর্ণ নাম লিখুন"
              value={donation.receiverName}
              onChange={(e) => setDonation({ ...donation, receiverName: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="গ্রহীতার মোবাইল নাম্বার"
              value={donation.receiverPhone}
              onChange={(e) => setDonation({ ...donation, receiverPhone: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="গ্রহীতার ঠিকানা"
              value={donation.receiverAddress}
              onChange={(e) => setDonation({ ...donation, receiverAddress: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              type="number"
              placeholder="দানের পরিমাণ (টাকা)"
              value={donation.amount}
              onChange={(e) => setDonation({ ...donation, amount: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="দানের কারণ লিখুন"
              value={donation.reason}
              onChange={(e) => setDonation({ ...donation, reason: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <button onClick={handleAddDonation} className="w-full bg-purple-600 text-white p-4 mt-3 rounded-xl">
              দান রেকর্ড করুন
            </button>
          </div>

          {/* EXPENSE */}
          <div className="bg-white p-8 rounded-3xl shadow-2xl">
            <h2 className="text-3xl font-bold mb-8 text-red-800 flex items-center gap-3">
              <ArrowDown /> খরচ রেকর্ড
            </h2>

            <input
              placeholder="যাকে টাকা দেওয়া হয়েছে তার নাম"
              value={expense.receiverName}
              onChange={(e) => setExpense({ ...expense, receiverName: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              type="number"
              placeholder="খরচের পরিমাণ (টাকা)"
              value={expense.amount}
              onChange={(e) => setExpense({ ...expense, amount: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <input
              placeholder="খরচের কারণ লিখুন"
              value={expense.reason}
              onChange={(e) => setExpense({ ...expense, reason: e.target.value })}
              className="w-full p-4 border mb-2"
            />

            <button onClick={handleAddExpense} className="w-full bg-red-600 text-white p-4 mt-3 rounded-xl">
              খরচ রেকর্ড করুন
            </button>
          </div>

        </div>
      </div>
    </div>
  );
}